tinymce.PluginManager.add('download', function(editor, url) {
    //  editor.ui.registry.addIcon('stream', '<svg class="icon"><use xlink:href="../../svg/custom-icons.svg#stream"></use></svg>');
    // editor.ui.registry.addIcon('stream', '<svg width="24" height="24"><use xlink:href="../../tinymce/svg/custom-icons.svg#stream"></use></svg>');
    editor.ui.registry.addIcon('download', '<?xml version="1.0" ?><svg height="16px" version="1.1" viewBox="0 0 16 16" width="16px" xmlns="http://www.w3.org/2000/svg" xmlns:sketch="http://www.bohemiancoding.com/sketch/ns" xmlns:xlink="http://www.w3.org/1999/xlink"><title/><defs/><g fill="none" fill-rule="evenodd" id="Icons with numbers" stroke="none" stroke-width="1"><g fill="#000000" id="Group" transform="translate(-720.000000, -432.000000)"><path d="M721,446 L733,446 L733,443 L735,443 L735,446 L735,448 L721,448 Z M721,443 L723,443 L723,446 L721,446 Z M726,433 L730,433 L730,440 L732,440 L728,445 L724,440 L726,440 Z M726,433" id="Rectangle 217"/></g></g></svg>');


    var openDialog = function () {
        var cid = editor.getParam('content_id');
        var ctype = editor.getParam('content_type');
        var module_code = editor.getParam('module_code');
        var query = '?cid='+cid+'&ctype='+ctype+'&moduleCode='+module_code;
        return editor.windowManager.openUrl({
            url: tinymce.baseURL + '/plugins/download/scripts/download.php'+ query,
            title: 'Download',
            width: 350,
            height: 350,

        });

    };


    editor.ui.registry.addButton('download', {
        tooltip: 'Download',
        icon: 'download',
        onAction: function () {
            // Open window
            openDialog();
        }

    });

    // Adds a menu item, which can then be included in any menu via the menu/menubar configuration
    editor.ui.registry.addMenuItem('download', {
        text: 'Download',
        icon: 'download',
        onAction: function () {
            // Open window
            openDialog();
        }
    });
});